        uniffiCheckContractApiVersion(this)
        uniffiCheckApiChecksums(this)
    }
    external fun uniffi_grafito_ffi_checksum_method_grafitoengine_camera_dolly(
    ): Short
    external fun uniffi_grafito_ffi_checksum_method_grafitoengine_camera_orbit(
    ): Short
    external fun uniffi_grafito_ffi_checksum_method_grafitoengine_canvas_pan(
    ): Short
    external fun uniffi_grafito_ffi_checksum_method_grafitoengine_canvas_tap(
