/**
 * @suppress
 */
public object FfiConverterTypeGrafitoEngine: FfiConverter<GrafitoEngine, Long> {
    override fun lower(value: GrafitoEngine): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): GrafitoEngine {
        return GrafitoEngine(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): GrafitoEngine {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: GrafitoEngine) = 8UL

    override fun write(value: GrafitoEngine, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



