sealed class CanvasException: kotlin.Exception() {
    
    class NotInitialized(
        ) : CanvasException() {
        override val message
            get() = ""
    }
    
    class SurfaceException(
        
        val v1: kotlin.String
        ) : CanvasException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class RenderException(
        
        val v1: kotlin.String
        ) : CanvasException() {
        override val message
            get() = "v1=${ v1 }"
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<CanvasException> {
        override fun lift(error_buf: RustBuffer.ByValue): CanvasException = FfiConverterTypeCanvasError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeCanvasError : FfiConverterRustBuffer<CanvasException> {
    override fun read(buf: ByteBuffer): CanvasException {
        

        return when(buf.getInt()) {
            1 -> CanvasException.NotInitialized()
            2 -> CanvasException.SurfaceException(
                FfiConverterString.read(buf),
                )
            3 -> CanvasException.RenderException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CanvasException): ULong {
        return when(value) {
            is CanvasException.NotInitialized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CanvasException.SurfaceException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is CanvasException.RenderException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
        }
    }

    override fun write(value: CanvasException, buf: ByteBuffer) {
        when(value) {
            is CanvasException.NotInitialized -> {
                buf.putInt(1)
                Unit
            }
            is CanvasException.SurfaceException -> {
                buf.putInt(2)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is CanvasException.RenderException -> {
                buf.putInt(3)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



